-- ===== ENUMS =====

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_type t JOIN pg_namespace n ON n.oid = t.typnamespace WHERE t.typname = 'bug_report_status' AND n.nspname = 'public') THEN
    CREATE TYPE public.bug_report_status AS ENUM ('new', 'triaged', 'fixed', 'wont_fix');
  END IF;
END $$;


