-- ===== TABLES (1-100) =====

CREATE TABLE IF NOT EXISTS public._slug_fix_log (
  id integer NOT NULL DEFAULT nextval('_slug_fix_log_id_seq'::regclass),
  note text,
  ts timestamp with time zone DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.ab_tests (
  id integer NOT NULL DEFAULT nextval('ab_tests_id_seq'::regclass),
  broker_slug text NOT NULL,
  name text NOT NULL,
  type text NOT NULL,
  status text NOT NULL DEFAULT 'draft'::text,
  variant_a jsonb NOT NULL DEFAULT '{}'::jsonb,
  variant_b jsonb NOT NULL DEFAULT '{}'::jsonb,
  traffic_split integer DEFAULT 50,
  impressions_a integer DEFAULT 0,
  impressions_b integer DEFAULT 0,
  clicks_a integer DEFAULT 0,
  clicks_b integer DEFAULT 0,
  conversions_a integer DEFAULT 0,
  conversions_b integer DEFAULT 0,
  winner text,
  start_date timestamp with time zone,
  end_date timestamp with time zone,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  auto_promoted_variant text,
  auto_promoted_at timestamp with time zone,
  min_sample_size integer DEFAULT 200,
  significance_threshold numeric DEFAULT 0.05,
  auto_promoted boolean NOT NULL DEFAULT false,
  PRIMARY KEY (id),
  CHECK ((status = ANY (ARRAY['draft'::text, 'running'::text, 'paused'::text, 'completed'::text]))),
  CHECK (((traffic_split >= 10) AND (traffic_split <= 90))),
  CHECK ((type = ANY (ARRAY['cta_text'::text, 'deal_text'::text, 'banner'::text, 'landing_page'::text]))),
  CHECK ((winner = ANY (ARRAY['a'::text, 'b'::text, NULL::text])))
);

