CREATE TABLE IF NOT EXISTS public.advisor_articles (
  id integer NOT NULL DEFAULT nextval('advisor_articles_id_seq'::regclass),
  professional_id integer NOT NULL,
  author_name text NOT NULL,
  author_firm text,
  author_slug text,
  title text NOT NULL,
  slug text,
  excerpt text,
  content text NOT NULL,
  category text DEFAULT 'General'::text,
  tags text[] DEFAULT '{}'::text[],
  cover_image_url text,
  status text NOT NULL DEFAULT 'draft'::text,
  admin_notes text,
  rejection_reason text,
  reviewed_by text,
  reviewed_at timestamp with time zone,
  published_at timestamp with time zone,
  pricing_tier text DEFAULT 'standard'::text,
  price_cents integer DEFAULT 29900,
  payment_status text DEFAULT 'unpaid'::text,
  payment_reference text,
  paid_at timestamp with time zone,
  meta_title text,
  meta_description text,
  canonical_url text,
  view_count integer DEFAULT 0,
  click_count integer DEFAULT 0,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  submitted_at timestamp with time zone,
  word_count integer DEFAULT 0,
  related_broker_slugs text[] DEFAULT '{}'::text[],
  related_advisor_types text[] DEFAULT '{}'::text[],
  featured boolean DEFAULT false,
  read_time integer DEFAULT 0,
  moderation_score integer DEFAULT 0,
  author_photo_url text,
  related_advisor_type text,
  reading_time_mins integer,
  related_brokers text[] DEFAULT '{}'::text[],
  lead_clicks integer DEFAULT 0,
  profile_clicks integer DEFAULT 0,
  share_count integer DEFAULT 0,
  avg_read_time_seconds integer DEFAULT 0,
  UNIQUE (slug),
  PRIMARY KEY (id),
  CHECK ((payment_status = ANY (ARRAY['unpaid'::text, 'paid'::text, 'waived'::text, 'refunded'::text]))),
  CHECK ((pricing_tier = ANY (ARRAY['standard'::text, 'featured'::text, 'sponsored'::text]))),
  CHECK ((status = ANY (ARRAY['draft'::text, 'submitted'::text, 'in_review'::text, 'revision_requested'::text, 'approved'::text, 'published'::text, 'rejected'::text])))
);

CREATE TABLE IF NOT EXISTS public.advisor_auction_bids (
