  PRIMARY KEY (id),
  CHECK ((bid_amount > 0)),
  CHECK ((status = ANY (ARRAY['active'::text, 'withdrawn'::text, 'accepted'::text, 'rejected'::text, 'expired'::text])))
);

CREATE TABLE IF NOT EXISTS public.advisor_auctions (
  id integer NOT NULL DEFAULT nextval('advisor_auctions_id_seq'::regclass),
  source text NOT NULL DEFAULT 'public_job'::text,
  flow_type text NOT NULL DEFAULT 'auction'::text,
  is_public boolean NOT NULL DEFAULT true,
  slug text NOT NULL,
  job_title text NOT NULL,
  job_description text,
  budget_band text,
  advisor_types text[] NOT NULL DEFAULT '{}'::text[],
  location text,
  contact_name text,
  contact_email text NOT NULL,
  contact_phone text,
  status text NOT NULL DEFAULT 'open'::text,
  ends_at timestamp with time zone NOT NULL,
  referrer_advisor_id integer,
  brief_template text,
  brief_payload jsonb NOT NULL DEFAULT '{}'::jsonb,
  provider_preference text,
  routing_mode text,
  target_professional_id integer,
  target_firm_id integer,
  target_team_id integer,
  accept_credits_cost integer,
  accepted_by_professional_id integer,
  accepted_by_team_id integer,
  accepted_at timestamp with time zone,
  tracker_status text NOT NULL DEFAULT 'new'::text,
  risk_flags text[] NOT NULL DEFAULT '{}'::text[],
  risk_review_status text NOT NULL DEFAULT 'clear'::text,
  listing_id integer,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  linked_action_plan_id bigint,
  created_by_user_id uuid,
  review_request_sent_at timestamp with time zone,
  expiry_reminder_sent_at timestamp with time zone,
  reopened_count integer NOT NULL DEFAULT 0,
  last_stale_check_at timestamp with time zone,
  auto_broadened_at timestamp with time zone,
  risk_review_resolved_at timestamp with time zone,
  risk_review_decided_by uuid,
  risk_review_decision_reason text,
  ai_quality_score integer,
  ai_quality_reason text,
  UNIQUE (slug),
  PRIMARY KEY (id),
  CHECK (((ai_quality_score IS NULL) OR ((ai_quality_score >= 1) AND (ai_quality_score <= 5)))),
  CHECK ((flow_type = ANY (ARRAY['auction'::text, 'accept'::text]))),
  CHECK (((provider_preference IS NULL) OR (provider_preference = ANY (ARRAY['any'::text, 'individual'::text, 'firm'::text, 'expert_team'::text, 'multiple'::text])))),
  CHECK ((risk_review_status = ANY (ARRAY['clear'::text, 'pending_review'::text, 'approved'::text, 'rejected'::text]))),
  CHECK (((routing_mode IS NULL) OR (routing_mode = ANY (ARRAY['smart_match'::text, 'direct'::text, 'multi_response'::text])))),
  CHECK ((status = ANY (ARRAY['open'::text, 'closed'::text, 'expired'::text, 'withdrawn'::text, 'awarded'::text]))),
  CHECK ((tracker_status = ANY (ARRAY['new'::text, 'contacted'::text, 'call_booked'::text, 'proposal_sent'::text, 'won'::text, 'lost'::text, 'withdrawn'::text])))
);

