  CHECK (((char_length(outcome) >= 20) AND (char_length(outcome) <= 500))),
  CHECK ((outcome_type = ANY (ARRAY['wealth_growth'::text, 'tax_saving'::text, 'debt_reduction'::text, 'retirement_planning'::text, 'insurance'::text, 'estate_planning'::text, 'business_succession'::text, 'other'::text]))),
  CHECK (((char_length(situation) >= 20) AND (char_length(situation) <= 1000))),
