  PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS public.advisor_office_hours (
  id bigint NOT NULL DEFAULT nextval('advisor_office_hours_id_seq'::regclass),
  advisor_id bigint NOT NULL,
  title text NOT NULL,
  description text,
  scheduled_at timestamp with time zone NOT NULL,
  ends_at timestamp with time zone,
  status text NOT NULL DEFAULT 'draft'::text,
  max_questions integer NOT NULL DEFAULT 20,
  rsvp_count integer NOT NULL DEFAULT 0,
  is_published boolean NOT NULL DEFAULT false,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK (((max_questions >= 1) AND (max_questions <= 100))),
  CHECK ((status = ANY (ARRAY['draft'::text, 'upcoming'::text, 'live'::text, 'ended'::text, 'transcript'::text]))),
  CHECK ((char_length(title) <= 200))
);

CREATE TABLE IF NOT EXISTS public.advisor_post_reactions (
  id integer NOT NULL DEFAULT nextval('advisor_post_reactions_id_seq'::regclass),
  post_id integer NOT NULL,
