  reaction_type text NOT NULL DEFAULT 'like'::text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  UNIQUE (post_id, user_id),
  PRIMARY KEY (id),
  CHECK ((reaction_type = ANY (ARRAY['like'::text, 'insightful'::text, 'celebrate'::text])))
);

CREATE TABLE IF NOT EXISTS public.advisor_posts (
  id integer NOT NULL DEFAULT nextval('advisor_posts_id_seq'::regclass),
  professional_id integer NOT NULL,
  body text NOT NULL,
  post_type text NOT NULL DEFAULT 'update'::text,
  link_url text,
  link_title text,
  image_url text,
  status text NOT NULL DEFAULT 'published'::text,
  reaction_count integer NOT NULL DEFAULT 0,
  comment_count integer NOT NULL DEFAULT 0,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK (((char_length(body) >= 1) AND (char_length(body) <= 2000))),
  CHECK ((post_type = ANY (ARRAY['update'::text, 'insight'::text, 'question'::text, 'resource'::text]))),
  CHECK ((status = ANY (ARRAY['published'::text, 'hidden'::text, 'deleted'::text])))
);

CREATE TABLE IF NOT EXISTS public.advisor_profile_views (
  id integer NOT NULL DEFAULT nextval('advisor_profile_views_id_seq'::regclass),
