CREATE TABLE IF NOT EXISTS public.articles (
  id bigint NOT NULL DEFAULT nextval('articles_id_seq'::regclass),
  title text NOT NULL,
  slug text NOT NULL,
  excerpt text,
  category text,
  content text,
  sections jsonb DEFAULT '[]'::jsonb,
  tags jsonb DEFAULT '[]'::jsonb,
  read_time integer,
  related_brokers jsonb DEFAULT '[]'::jsonb,
  related_calc text,
  evergreen boolean DEFAULT true,
  published_at timestamp with time zone,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  author_name text DEFAULT 'Market Research Team'::text,
  author_title text DEFAULT 'Invest.com.au'::text,
  author_linkedin text,
  author_twitter text,
  status text DEFAULT 'published'::text,
  author_id bigint,
  reviewer_id bigint,
  reviewed_at timestamp with time zone,
  changelog jsonb DEFAULT '[]'::jsonb,
  publish_date timestamp with time zone,
  meta_title text,
  meta_description text,
  author_image text,
  featured boolean DEFAULT false,
  cover_image_url text,
  last_audited_at timestamp with time zone,
  staleness_score integer DEFAULT 0,
  needs_update boolean DEFAULT false,
  content_type text DEFAULT 'editorial'::text,
  related_advisor_types text[] DEFAULT '{}'::text[],
  related_verticals text[] DEFAULT '{}'::text[],
  last_reviewed_at timestamp with time zone,
  last_reviewed_by text,
  primary_broker_ids bigint[] DEFAULT '{}'::bigint[],
  expected_rev_per_visit numeric DEFAULT 0,
  total_visits integer DEFAULT 0,
  total_affiliate_clicks integer DEFAULT 0,
  total_conversions integer DEFAULT 0,
  total_revenue_cents integer DEFAULT 0,
  target_keyword text,
  search_vec tsvector GENERATED ALWAYS AS ((((setweight(to_tsvector('english'::regconfig, COALESCE(title, ''::text)), 'A'::"char") || setweight(to_tsvector('english'::regconfig, COALESCE(excerpt, ''::text)), 'B'::"char")) || setweight(to_tsvector('english'::regconfig, COALESCE(category, ''::text)), 'C'::"char")) || setweight(to_tsvector('english'::regconfig, COALESCE(target_keyword, ''::text)), 'B'::"char"))) STORED,
  author_photo_url text,
  link_density_override smallint,
  UNIQUE (slug),
  PRIMARY KEY (id),
  CHECK (((link_density_override IS NULL) OR ((link_density_override >= 0) AND (link_density_override <= 20))))
);

