CREATE TABLE IF NOT EXISTS public.bd_pipeline (
  id integer NOT NULL DEFAULT nextval('bd_pipeline_id_seq'::regclass),
  company_name text NOT NULL,
  contact_name text,
  contact_email text,
  contact_linkedin text,
  partnership_type text DEFAULT 'affiliate'::text,
  status text DEFAULT 'cold'::text,
  cpa_rate text,
  deal_notes text,
  next_action text,
  next_action_date date,
  last_contact_date date,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS public.best_for_scenarios (
  id bigint NOT NULL DEFAULT nextval('best_for_scenarios_id_seq'::regclass),
  slug text NOT NULL,
  h1 text NOT NULL,
  intro text NOT NULL,
  meta_description text NOT NULL,
  scoring_weights jsonb NOT NULL,
  required_attrs text[] NOT NULL DEFAULT '{}'::text[],
  category_filter text,
  target_user text NOT NULL,
  body_sections jsonb,
  status text NOT NULL DEFAULT 'active'::text,
  display_order integer NOT NULL DEFAULT 100,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  UNIQUE (slug),
  PRIMARY KEY (id),
  CHECK ((status = ANY (ARRAY['active'::text, 'draft'::text, 'retired'::text])))
);

CREATE TABLE IF NOT EXISTS public.booking_payments (
  id bigint NOT NULL DEFAULT nextval('booking_payments_id_seq'::regclass),
  slot_id bigint NOT NULL,
  professional_id bigint NOT NULL,
  consumer_email text NOT NULL,
  consumer_user_id uuid,
  amount_cents integer NOT NULL,
  platform_fee_cents integer NOT NULL,
  currency text NOT NULL DEFAULT 'aud'::text,
  stripe_checkout_session_id text,
  stripe_payment_intent_id text,
  status text NOT NULL DEFAULT 'pending'::text,
  description text,
  metadata jsonb NOT NULL DEFAULT '{}'::jsonb,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  UNIQUE (stripe_checkout_session_id),
  PRIMARY KEY (id),
  CHECK ((status = ANY (ARRAY['pending'::text, 'paid'::text, 'failed'::text, 'refunded'::text, 'cancelled'::text])))
);

CREATE TABLE IF NOT EXISTS public.brief_credit_prices (
  id integer NOT NULL DEFAULT nextval('brief_credit_prices_id_seq'::regclass),
  brief_template text NOT NULL,
  provider_type text NOT NULL DEFAULT 'any'::text,
  credits_cost integer NOT NULL,
  notes text,
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_by text,
  UNIQUE (brief_template, provider_type),
  PRIMARY KEY (id),
  CHECK ((credits_cost >= 0)),
  CHECK ((provider_type = ANY (ARRAY['any'::text, 'individual'::text, 'firm'::text, 'expert_team'::text])))
);

CREATE TABLE IF NOT EXISTS public.brief_dispute_messages (
  id bigint NOT NULL DEFAULT nextval('brief_dispute_messages_id_seq'::regclass),
  dispute_id bigint NOT NULL,
  sender_kind text NOT NULL,
  sender_user_id uuid,
  body text NOT NULL,
  evidence_urls text[] NOT NULL DEFAULT '{}'::text[],
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK (((length(body) > 0) AND (length(body) <= 4000))),
  CHECK ((sender_kind = ANY (ARRAY['consumer'::text, 'professional'::text, 'team'::text, 'admin'::text])))
);

CREATE TABLE IF NOT EXISTS public.brief_disputes (
  id bigint NOT NULL DEFAULT nextval('brief_disputes_id_seq'::regclass),
  brief_id integer NOT NULL,
  opened_by_kind text NOT NULL,
  opened_by_user_id uuid,
  opened_by_email text NOT NULL,
  reason text NOT NULL,
  evidence_urls text[] NOT NULL DEFAULT '{}'::text[],
  status text NOT NULL DEFAULT 'open'::text,
  resolution_notes text,
  resolved_at timestamp with time zone,
  resolved_by_user_id uuid,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  UNIQUE (brief_id),
  PRIMARY KEY (id),
  CHECK ((opened_by_kind = ANY (ARRAY['consumer'::text, 'professional'::text, 'team'::text]))),
  CHECK (((length(reason) >= 200) AND (length(reason) <= 4000))),
  CHECK ((status = ANY (ARRAY['open'::text, 'admin_reviewing'::text, 'resolved_for_consumer'::text, 'resolved_for_provider'::text, 'withdrawn'::text])))
);

CREATE TABLE IF NOT EXISTS public.brief_messages (
  id bigint NOT NULL DEFAULT nextval('brief_messages_id_seq'::regclass),
  brief_id integer NOT NULL,
  sender_kind text NOT NULL,
  sender_user_id uuid,
  sender_professional_id integer,
  sender_team_id integer,
  body text NOT NULL,
  read_by_consumer_at timestamp with time zone,
  read_by_pro_at timestamp with time zone,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK (((length(body) > 0) AND (length(body) <= 4000))),
  CHECK ((sender_kind = ANY (ARRAY['consumer'::text, 'professional'::text, 'team'::text])))
);

CREATE TABLE IF NOT EXISTS public.brief_outcomes (
  id bigint NOT NULL DEFAULT nextval('brief_outcomes_id_seq'::regclass),
  brief_id integer NOT NULL,
  consumer_email text NOT NULL,
  auth_user_id uuid,
  professional_id integer,
  team_id integer,
  outcome text NOT NULL,
  rating integer,
  testimonial text,
  show_testimonial boolean NOT NULL DEFAULT false,
  review_token text NOT NULL,
  review_requested_at timestamp with time zone,
  submitted_at timestamp with time zone,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  UNIQUE (brief_id),
  UNIQUE (review_token),
  PRIMARY KEY (id),
  CHECK ((outcome = ANY (ARRAY['completed'::text, 'in_progress'::text, 'switched_providers'::text, 'abandoned'::text]))),
  CHECK (((rating IS NULL) OR ((rating >= 1) AND (rating <= 5))))
);

CREATE TABLE IF NOT EXISTS public.brief_promo_codes (
  id bigint NOT NULL DEFAULT nextval('brief_promo_codes_id_seq'::regclass),
  code text NOT NULL,
  code_kind text NOT NULL,
  value numeric,
  max_uses integer NOT NULL DEFAULT 1,
  used_count integer NOT NULL DEFAULT 0,
  expires_at timestamp with time zone,
  created_by_admin text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  notes text,
  UNIQUE (code),
  PRIMARY KEY (id),
  CHECK ((code_kind = ANY (ARRAY['free_brief'::text, 'percent_off_accept'::text, 'fixed_credits'::text]))),
  CHECK ((max_uses >= 1)),
  CHECK ((used_count >= 0)),
  CHECK ((used_count <= max_uses)),
  CHECK (((code_kind <> 'fixed_credits'::text) OR (value > (0)::numeric))),
  CHECK (((code_kind <> 'percent_off_accept'::text) OR ((value > (0)::numeric) AND (value <= (100)::numeric)))),
  CHECK (((code_kind = 'free_brief'::text) OR (value IS NOT NULL)))
);

CREATE TABLE IF NOT EXISTS public.brief_promo_redemptions (
  id bigint NOT NULL DEFAULT nextval('brief_promo_redemptions_id_seq'::regclass),
  promo_code_id bigint NOT NULL,
  brief_id bigint NOT NULL,
  redeemed_at timestamp with time zone NOT NULL DEFAULT now(),
  contact_email text,
  UNIQUE (promo_code_id, brief_id),
  PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS public.brief_risk_patterns (
  id integer NOT NULL DEFAULT nextval('brief_risk_patterns_id_seq'::regclass),
