  updated_by text,
  PRIMARY KEY (id)
);

CREATE TABLE IF NOT EXISTS public.brief_shortlists (
  id bigint NOT NULL DEFAULT nextval('brief_shortlists_id_seq'::regclass),
  brief_id integer NOT NULL,
  provider_kind text NOT NULL,
  provider_id integer NOT NULL,
  added_by_user_id uuid,
  added_by_email text NOT NULL,
  note text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK ((provider_kind = ANY (ARRAY['professional'::text, 'team'::text])))
);

CREATE TABLE IF NOT EXISTS public.brief_tracker_events (
  id bigint NOT NULL DEFAULT nextval('brief_tracker_events_id_seq'::regclass),
