  requires_australian_address boolean,
  accepts_temporary_residents boolean,
  search_vec tsvector GENERATED ALWAYS AS (((setweight(to_tsvector('english'::regconfig, COALESCE(name, ''::text)), 'A'::"char") || setweight(to_tsvector('english'::regconfig, COALESCE(tagline, ''::text)), 'B'::"char")) || setweight(to_tsvector('english'::regconfig, COALESCE(slug, ''::text)), 'C'::"char"))) STORED,
  country_eligibility jsonb NOT NULL DEFAULT '{}'::jsonb,
  UNIQUE (slug),
  PRIMARY KEY (id),
  CHECK ((affiliate_priority = ANY (ARRAY['high'::text, 'medium'::text, 'low'::text]))),
  CHECK (((jsonb_typeof(country_eligibility) = 'object'::text) AND ((NOT (country_eligibility ? 'allowed_countries'::text)) OR (jsonb_typeof((country_eligibility -> 'allowed_countries'::text)) = 'array'::text)) AND ((NOT (country_eligibility ? 'blocked_countries'::text)) OR (jsonb_typeof((country_eligibility -> 'blocked_countries'::text)) = 'array'::text)) AND ((NOT (country_eligibility ? 'visa_required'::text)) OR (jsonb_typeof((country_eligibility -> 'visa_required'::text)) = 'array'::text)) AND ((NOT (country_eligibility ? 'verified_at'::text)) OR (jsonb_typeof((country_eligibility -> 'verified_at'::text)) = 'string'::text)) AND ((NOT (country_eligibility ? 'notes'::text)) OR (jsonb_typeof((country_eligibility -> 'notes'::text)) = ANY (ARRAY['string'::text, 'null'::text]))))),
  CHECK ((sponsorship_tier = ANY (ARRAY['featured_partner'::text, 'editors_pick'::text, 'deal_of_month'::text]))),
  CHECK ((status = ANY (ARRAY['active'::text, 'draft'::text])))
);

