  CHECK ((status = ANY (ARRAY['published'::text, 'hidden'::text, 'deleted'::text])))
);

CREATE TABLE IF NOT EXISTS public.courses (
  id bigint NOT NULL DEFAULT nextval('courses_id_seq'::regclass),
