  cpd_category text DEFAULT 'technical'::text,
  is_cpd_eligible boolean NOT NULL DEFAULT false,
  creator_kind text NOT NULL DEFAULT 'team'::text,
  organisation_id integer,
  is_advisor_created boolean NOT NULL DEFAULT false,
  advisor_professional_id integer,
