  CHECK ((cpd_category = ANY (ARRAY['technical'::text, 'conduct'::text, 'client_care'::text, 'regulatory'::text]))),
  CHECK ((creator_kind = ANY (ARRAY['team'::text, 'advisor'::text, 'organisation'::text]))),
  CHECK ((level = ANY (ARRAY['beginner'::text, 'intermediate'::text, 'advanced'::text]))),
  CHECK ((status = ANY (ARRAY['draft'::text, 'published'::text, 'archived'::text])))
);

