  id integer NOT NULL DEFAULT nextval('forum_posts_id_seq'::regclass),
  thread_id integer NOT NULL,
  body text NOT NULL,
  author_id uuid,
  author_name text,
  is_removed boolean DEFAULT false,
  is_moderator boolean DEFAULT false,
  vote_score integer DEFAULT 0,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  is_anonymous boolean NOT NULL DEFAULT false,
  post_type text NOT NULL DEFAULT 'reply'::text,
  debate_position text,
  PRIMARY KEY (id),
  CHECK (((debate_position IS NULL) OR (debate_position = ANY (ARRAY['bull'::text, 'bear'::text])))),
  CHECK ((post_type = ANY (ARRAY['reply'::text, 'debate'::text])))
);

CREATE TABLE IF NOT EXISTS public.forum_reports (
  id bigint NOT NULL DEFAULT nextval('forum_reports_id_seq'::regclass),
