);

CREATE TABLE IF NOT EXISTS public.fund_reviews (
  id integer NOT NULL DEFAULT nextval('fund_reviews_id_seq'::regclass),
  fund_id integer NOT NULL,
  fund_slug text NOT NULL,
  display_name text NOT NULL,
  email text NOT NULL,
  rating integer NOT NULL,
  title text NOT NULL,
  body text NOT NULL,
  pros text,
  cons text,
  performance_rating integer,
  communication_rating integer,
  fees_rating integer,
  manager_rating integer,
  hold_period_months integer,
  status text NOT NULL DEFAULT 'pending'::text,
  verification_token text,
  verified_at timestamp with time zone,
  moderation_note text,
  ip_hash text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK (((communication_rating IS NULL) OR ((communication_rating >= 1) AND (communication_rating <= 5)))),
  CHECK (((fees_rating IS NULL) OR ((fees_rating >= 1) AND (fees_rating <= 5)))),
  CHECK (((hold_period_months IS NULL) OR (hold_period_months >= 1))),
  CHECK (((manager_rating IS NULL) OR ((manager_rating >= 1) AND (manager_rating <= 5)))),
  CHECK (((performance_rating IS NULL) OR ((performance_rating >= 1) AND (performance_rating <= 5)))),
  CHECK (((rating >= 1) AND (rating <= 5))),
  CHECK ((status = ANY (ARRAY['pending'::text, 'verified'::text, 'approved'::text, 'rejected'::text])))
);

