  id bigint GENERATED ALWAYS AS IDENTITY,
  ticker text NOT NULL,
  exchange text NOT NULL,
  price_cents bigint NOT NULL,
  currency text NOT NULL,
  source text NOT NULL,
  fetched_at timestamp with time zone NOT NULL DEFAULT now(),
  last_attempt_at timestamp with time zone NOT NULL DEFAULT now(),
  UNIQUE (ticker, exchange),
  PRIMARY KEY (id),
  CHECK ((length(currency) = 3)),
  CHECK ((exchange = ANY (ARRAY['ASX'::text, 'NASDAQ'::text, 'NYSE'::text, 'LSE'::text, 'HKEX'::text, 'SGX'::text, 'TYO'::text, 'KRX'::text, 'CRYPTO'::text, 'OTHER'::text]))),
  CHECK ((price_cents >= 0)),
  CHECK ((source = ANY (ARRAY['yahoo'::text, 'coingecko'::text, 'manual'::text, 'stale'::text]))),
  CHECK (((length(ticker) > 0) AND (length(ticker) <= 30)))
);

