  CHECK (((listing_kind IS NULL) OR (listing_kind = ANY (ARRAY['for_sale_business'::text, 'for_sale_asset'::text, 'equity_raise'::text, 'project_equity'::text, 'royalty'::text, 'fund'::text, 'physical_asset'::text, 'listed_security'::text]))))
