  notes text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK ((current_balance_cents >= 0)),
  CHECK (((expected_return_pct >= ('-10'::integer)::numeric) AND (expected_return_pct <= (30)::numeric))),
  CHECK ((goal_type = ANY (ARRAY['house_deposit'::text, 'retirement'::text, 'education'::text, 'generic'::text, 'fire'::text, 'debt_free'::text]))),
  CHECK (((length(label) > 0) AND (length(label) <= 120))),
  CHECK ((monthly_contribution_cents >= 0)),
  CHECK (((notes IS NULL) OR (length(notes) <= 500))),
  CHECK ((target_cents >= 0))
);

