  CHECK (((intent_country_snapshot IS NULL) OR (intent_country_snapshot = ANY (ARRAY['uk'::text, 'us'::text, 'cn'::text, 'in'::text, 'jp'::text, 'sg'::text, 'hk'::text, 'kr'::text, 'my'::text, 'nz'::text, 'ae'::text, 'sa'::text]))))
