  professional_id integer NOT NULL,
  reason text NOT NULL,
  details text,
  status text DEFAULT 'pending'::text,
  admin_notes text,
  billing_id integer,
  created_at timestamp with time zone DEFAULT now(),
  resolved_at timestamp with time zone,
  reason_code text,
  auto_resolved_at timestamp with time zone,
  auto_resolved_verdict text,
  auto_resolved_confidence text,
  auto_resolved_reasons jsonb,
  refunded_cents integer DEFAULT 0,
  admin_overridden_at timestamp with time zone,
  admin_overridden_by text,
  admin_override_reason text,
  PRIMARY KEY (id),
  CHECK (((auto_resolved_confidence IS NULL) OR (auto_resolved_confidence = ANY (ARRAY['high'::text, 'medium'::text, 'low'::text])))),
  CHECK (((auto_resolved_verdict IS NULL) OR (auto_resolved_verdict = ANY (ARRAY['refund'::text, 'reject'::text, 'escalate'::text])))),
  CHECK ((reason = ANY (ARRAY['spam'::text, 'wrong_number'::text, 'fake_details'::text, 'not_genuine'::text, 'duplicate'::text, 'other'::text]))),
  CHECK (((reason_code IS NULL) OR (reason_code = ANY (ARRAY['spam_or_fake'::text, 'wrong_specialty'::text, 'out_of_area'::text, 'unreachable'::text, 'duplicate'::text, 'under_minimum'::text, 'other'::text])))),
  CHECK ((status = ANY (ARRAY['pending'::text, 'approved'::text, 'rejected'::text])))
);

