  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  approved_at timestamp with time zone,
  rejected_at timestamp with time zone,
  UNIQUE (slug),
  PRIMARY KEY (id),
  CHECK ((kind = ANY (ARRAY['property'::text, 'business'::text, 'syndicate'::text, 'asset_other'::text]))),
  CHECK ((status = ANY (ARRAY['draft'::text, 'pending_review'::text, 'approved'::text, 'rejected'::text, 'archived'::text])))
);

CREATE TABLE IF NOT EXISTS public.llm_citations (
