  CHECK ((llm_provider = ANY (ARRAY['chatgpt'::text, 'claude'::text, 'gemini'::text, 'perplexity'::text, 'copilot'::text, 'grok'::text, 'other'::text])))
);

CREATE TABLE IF NOT EXISTS public.login_attempts (
