);

CREATE TABLE IF NOT EXISTS public.manual_balances (
  id uuid NOT NULL DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  label text NOT NULL,
  amount_cents bigint NOT NULL DEFAULT 0,
  category text NOT NULL,
