  PRIMARY KEY (id),
  CHECK ((amount_cents >= 0)),
  CHECK ((category = ANY (ARRAY['savings'::text, 'super'::text, 'property'::text, 'other'::text]))),
  CHECK ((length(TRIM(BOTH FROM label)) > 0))
);

CREATE TABLE IF NOT EXISTS public.market_events (
  id bigint NOT NULL DEFAULT nextval('market_events_id_seq'::regclass),
