  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK ((event_type = ANY (ARRAY['rba'::text, 'asx'::text, 'earnings'::text, 'economic'::text, 'dividend'::text, 'ipo'::text, 'other'::text])))
);

CREATE TABLE IF NOT EXISTS public.marketplace_invoices (
