  type text NOT NULL,
  status text NOT NULL DEFAULT 'pending'::text,
  stripe_payment_intent_id text,
  stripe_checkout_session_id text,
  description text,
  paid_at timestamp with time zone,
  created_at timestamp with time zone DEFAULT now(),
  invoice_number text,
  line_items jsonb DEFAULT '[]'::jsonb,
  tax_cents bigint DEFAULT 0,
  subtotal_cents bigint,
  broker_company_name text,
  broker_email text,
  broker_abn text,
  PRIMARY KEY (id),
  CHECK ((status = ANY (ARRAY['pending'::text, 'paid'::text, 'failed'::text, 'refunded'::text]))),
  CHECK ((type = ANY (ARRAY['wallet_topup'::text, 'manual_adjustment'::text])))
);

CREATE TABLE IF NOT EXISTS public.marketplace_payments (
  id bigint NOT NULL DEFAULT nextval('marketplace_payments_id_seq'::regclass),
