  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  UNIQUE (source_url),
  PRIMARY KEY (id),
  CHECK ((redirect_code = ANY (ARRAY[301, 302, 307, 308]))),
  CHECK ((status = ANY (ARRAY['mapped'::text, 'verified'::text, 'migrated'::text, 'failed'::text, 'skipped'::text]))),
  CHECK ((url_type = ANY (ARRAY['page'::text, 'asset'::text, 'feed'::text, 'api'::text, 'redirect_only'::text])))
);

CREATE TABLE IF NOT EXISTS public.morning_brief_sends (
