  CHECK ((stripe_connect_status = ANY (ARRAY['not_connected'::text, 'onboarding'::text, 'active'::text, 'restricted'::text, 'rejected'::text]))),
  CHECK ((tier = ANY (ARRAY['free'::text, 'starter'::text, 'growth'::text, 'featured'::text]))),
  CHECK ((verification_status = ANY (ARRAY['unverified'::text, 'pending'::text, 'verified'::text])))
);

