  verified_client_at timestamp with time zone,
  verified_engagement boolean NOT NULL DEFAULT false,
  verified_at timestamp with time zone,
  PRIMARY KEY (id),
  CHECK (((communication_rating IS NULL) OR ((communication_rating >= 1) AND (communication_rating <= 5)))),
  CHECK (((expertise_rating IS NULL) OR ((expertise_rating >= 1) AND (expertise_rating <= 5)))),
  CHECK (((value_for_money_rating IS NULL) OR ((value_for_money_rating >= 1) AND (value_for_money_rating <= 5)))),
  CHECK (((auto_moderated_verdict IS NULL) OR (auto_moderated_verdict = ANY (ARRAY['auto_publish'::text, 'auto_reject'::text, 'escalate'::text])))),
  CHECK (((rating >= 1) AND (rating <= 5))),
  CHECK ((status = ANY (ARRAY['pending'::text, 'approved'::text, 'rejected'::text])))
);

