  is_investment_property boolean NOT NULL DEFAULT false,
  weekly_rent_cents bigint,
  loan_balance_cents bigint,
  loan_rate_pct numeric(5,3),
  property_type text,
  notes text,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  PRIMARY KEY (id),
  CHECK (((length(address_line) > 0) AND (length(address_line) <= 200))),
  CHECK (((current_value_estimate_cents IS NULL) OR (current_value_estimate_cents >= 0))),
  CHECK (((loan_balance_cents IS NULL) OR (loan_balance_cents >= 0))),
  CHECK (((loan_rate_pct IS NULL) OR ((loan_rate_pct >= (0)::numeric) AND (loan_rate_pct <= (99)::numeric)))),
  CHECK (((notes IS NULL) OR (length(notes) <= 500))),
  CHECK (((property_type IS NULL) OR (property_type = ANY (ARRAY['house'::text, 'apartment'::text, 'townhouse'::text, 'commercial'::text, 'land'::text, 'rural'::text, 'other'::text])))),
  CHECK ((purchase_price_cents >= 0)),
  CHECK (((state IS NULL) OR (state = ANY (ARRAY['NSW'::text, 'VIC'::text, 'QLD'::text, 'WA'::text, 'SA'::text, 'TAS'::text, 'NT'::text, 'ACT'::text])))),
