CREATE TABLE IF NOT EXISTS public.rate_alert_subscriptions (
  id uuid NOT NULL DEFAULT gen_random_uuid(),
  email text NOT NULL,
  product_kind text NOT NULL,
  threshold_bps integer NOT NULL,
  product_filters jsonb NOT NULL DEFAULT '{}'::jsonb,
  frequency text NOT NULL DEFAULT 'instant'::text,
  verified boolean NOT NULL DEFAULT false,
  verify_token text NOT NULL,
  unsubscribe_token text NOT NULL,
  last_notified_at timestamp with time zone,
  notification_count integer NOT NULL DEFAULT 0,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now(),
  user_id uuid,
  metric_kind text,
  direction text NOT NULL DEFAULT 'above'::text,
  broker_slug text,
  lender_slug text,
  last_fired_value_bps integer,
  PRIMARY KEY (id),
  CHECK ((direction = ANY (ARRAY['above'::text, 'below'::text]))),
  CHECK ((frequency = ANY (ARRAY['instant'::text, 'daily'::text, 'weekly'::text]))),
  CHECK (((metric_kind IS NULL) OR (metric_kind = ANY (ARRAY['savings_rate'::text, 'term_deposit'::text, 'loan_rate'::text, 'broker_fee'::text])))),
  CHECK ((product_kind = ANY (ARRAY['savings_account'::text, 'term_deposit'::text]))),
  CHECK (((threshold_bps >= 0) AND (threshold_bps <= 10000)))
);

