  CHECK (((comment IS NULL) OR (length(comment) <= 500))),
  CHECK ((product_kind = ANY (ARRAY['savings'::text, 'term_deposit'::text]))),
  CHECK ((status = ANY (ARRAY['pending'::text, 'verified'::text, 'rejected'::text]))),
  CHECK (((term_months IS NULL) OR ((term_months > 0) AND (term_months <= 120)))),
  CHECK (((verified_rate_bps > 0) AND (verified_rate_bps < 5000)))
);

