  page text NOT NULL DEFAULT '/compare'::text,
  status text DEFAULT 'draft'::text,
  variant_a jsonb NOT NULL DEFAULT '{}'::jsonb,
  variant_b jsonb NOT NULL DEFAULT '{}'::jsonb,
  traffic_split integer DEFAULT 50,
  impressions_a integer DEFAULT 0,
  impressions_b integer DEFAULT 0,
  clicks_a integer DEFAULT 0,
  clicks_b integer DEFAULT 0,
  conversions_a integer DEFAULT 0,
  conversions_b integer DEFAULT 0,
  winner text,
  start_date timestamp with time zone,
  end_date timestamp with time zone,
  created_by text,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  PRIMARY KEY (id),
  CHECK ((status = ANY (ARRAY['draft'::text, 'running'::text, 'paused'::text, 'completed'::text]))),
  CHECK ((test_type = ANY (ARRAY['cta_copy'::text, 'cta_color'::text, 'cta_placement'::text, 'layout'::text, 'redirect_vs_apply'::text]))),
  CHECK (((traffic_split >= 1) AND (traffic_split <= 99))),
  CHECK ((winner = ANY (ARRAY['a'::text, 'b'::text])))
);

