  next_retry_at timestamp with time zone DEFAULT now(),
  last_error text,
  status text DEFAULT 'pending'::text,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.weekly_rate_drip_log (
  id bigint NOT NULL DEFAULT nextval('weekly_rate_drip_log_id_seq'::regclass),
  email_capture_id bigint NOT NULL,
  sent_at timestamp with time zone DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.weights (
  broker_slug text NOT NULL,
  weights jsonb NOT NULL DEFAULT '{}'::jsonb,
  updated_at timestamp with time zone NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.widget_licenses (
  id uuid NOT NULL DEFAULT gen_random_uuid(),
  api_key_id uuid NOT NULL,
  name text NOT NULL DEFAULT ''::text,
  token_hash text NOT NULL,
  token_prefix text NOT NULL,
  allowed_domains text[] NOT NULL DEFAULT '{}'::text[],
  is_active boolean NOT NULL DEFAULT true,
  created_at timestamp with time zone NOT NULL DEFAULT now(),
  updated_at timestamp with time zone NOT NULL DEFAULT now()
);


