CREATE OR REPLACE FUNCTION public.advisor_fee_stats(p_type text DEFAULT NULL::text)
 RETURNS TABLE(advisor_type text, avg_hourly_cents integer, min_hourly_cents integer, max_hourly_cents integer, avg_flat_fee_cents integer, min_flat_fee_cents integer, max_flat_fee_cents integer, avg_aum_pct numeric, advisor_count bigint)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    p.type AS advisor_type,
    AVG(p.hourly_rate_cents)::integer,
    MIN(p.hourly_rate_cents),
    MAX(p.hourly_rate_cents),
    AVG(p.flat_fee_cents)::integer,
    MIN(p.flat_fee_cents),
    MAX(p.flat_fee_cents),
    ROUND(AVG(p.aum_percentage), 2),
    COUNT(*)
  FROM professionals p
  WHERE p.status = 'active'
    AND (p_type IS NULL OR p.type = p_type)
    AND (p.hourly_rate_cents IS NOT NULL OR p.flat_fee_cents IS NOT NULL OR p.aum_percentage IS NOT NULL)
  GROUP BY p.type
  ORDER BY p.type;
END;
$function$;

CREATE OR REPLACE FUNCTION public.auto_bill_lead()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_advisor_type TEXT;
  v_price INTEGER;
BEGIN
  SELECT type INTO v_advisor_type
  FROM public.professionals WHERE id = NEW.professional_id;

  SELECT price_cents INTO v_price
  FROM public.lead_pricing WHERE advisor_type = v_advisor_type;

  IF v_price IS NULL OR v_price = 0 THEN
    RETURN NEW;
  END IF;

  UPDATE public.professional_leads SET lead_value = v_price / 100.0 WHERE id = NEW.id;

  INSERT INTO public.advisor_billing (professional_id, lead_id, amount_cents, description, status)
  VALUES (
    NEW.professional_id,
    NEW.id,
    v_price,
    'Lead from ' || COALESCE(NEW.user_name, 'Unknown') || ' via ' || COALESCE(NEW.source_page, 'direct'),
    'pending'
  );

  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.calculate_broker_revenue_score(p_rating numeric, p_cpa_value integer, p_has_deal boolean, p_has_chess boolean, p_promoted boolean, p_editors_pick boolean)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE score NUMERIC;
BEGIN
  score := (COALESCE(p_rating, 0) * 0.3) + ((COALESCE(p_cpa_value, 0)::NUMERIC / 50.0) * 0.4)
    + (CASE WHEN p_has_deal THEN 1.5 ELSE 0 END) + (CASE WHEN p_has_chess THEN 0.5 ELSE 0 END)
    + (CASE WHEN p_promoted THEN 3.0 ELSE 0 END) + (CASE WHEN p_editors_pick THEN 1.0 ELSE 0 END);
  RETURN score;
END;
$function$;

CREATE OR REPLACE FUNCTION public.cleanup_expired_data()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Delete expired auth tokens (older than 1 hour)
  DELETE FROM advisor_auth_tokens WHERE expires_at < NOW() - INTERVAL '1 hour';

  -- Delete expired sessions (older than their expiry)
  DELETE FROM advisor_sessions WHERE expires_at < NOW();

  -- Delete old rate limit entries (older than 2 hours)
  DELETE FROM rate_limits WHERE window_start < NOW() - INTERVAL '2 hours';
END;
$function$;

CREATE OR REPLACE FUNCTION public.cleanup_old_analytics()
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  DELETE FROM analytics_events WHERE created_at < NOW() - INTERVAL '90 days';
  DELETE FROM affiliate_clicks WHERE created_at < NOW() - INTERVAL '365 days';
END;
$function$;

CREATE OR REPLACE FUNCTION public.cleanup_rate_limits()
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  DELETE FROM rate_limits WHERE window_start < NOW() - INTERVAL '1 hour';
END;
$function$;

CREATE OR REPLACE FUNCTION public.decrement_oh_upvote(question_id_arg bigint)
 RETURNS void
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  UPDATE office_hour_questions
  SET upvote_count = GREATEST(0, upvote_count - 1)
  WHERE id = question_id_arg;
$function$;

CREATE OR REPLACE FUNCTION public.generate_advisor_article_slug()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.slug IS NULL OR NEW.slug = '' THEN
    NEW.slug := LOWER(REGEXP_REPLACE(REGEXP_REPLACE(NEW.title, '[^a-zA-Z0-9\s-]', '', 'g'), '\s+', '-', 'g'));
    -- Ensure uniqueness
    WHILE EXISTS (SELECT 1 FROM advisor_articles WHERE slug = NEW.slug AND id != COALESCE(NEW.id, 0)) LOOP
      NEW.slug := NEW.slug || '-' || FLOOR(RANDOM() * 1000)::TEXT;
    END LOOP;
  END IF;
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.generate_invoice_number()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  NEW.invoice_number := 'INV-' || TO_CHAR(NOW(), 'YYYYMM') || '-' || LPAD(NEW.id::TEXT, 5, '0');
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.get_broker_percentile(p_broker_slug text, p_date_from date)
 RETURNS TABLE(metric text, broker_value numeric, percentile_rank numeric, total_brokers integer)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH broker_metrics AS (
    SELECT
      broker_slug,
      CASE WHEN SUM(impressions) > 0 THEN (SUM(clicks)::numeric / SUM(impressions)) * 100 ELSE 0 END AS ctr,
      CASE WHEN SUM(clicks) > 0 THEN SUM(spend_cents)::numeric / SUM(clicks) / 100 ELSE 0 END AS cpc,
      CASE WHEN SUM(clicks) > 0 THEN (SUM(conversions)::numeric / SUM(clicks)) * 100 ELSE 0 END AS conv_rate
    FROM campaign_daily_stats
    WHERE stat_date >= p_date_from
    GROUP BY broker_slug
    HAVING SUM(clicks) >= 10
  ),
  broker_count AS (SELECT COUNT(*)::int AS cnt FROM broker_metrics)
  SELECT 'ctr'::text, bm.ctr,
    ROUND((PERCENT_RANK() OVER (ORDER BY bm.ctr) * 100)::numeric, 1),
    bc.cnt
  FROM broker_metrics bm, broker_count bc WHERE bm.broker_slug = p_broker_slug
  UNION ALL
  SELECT 'cpc'::text, bm.cpc,
    ROUND((PERCENT_RANK() OVER (ORDER BY bm.cpc DESC) * 100)::numeric, 1),
    bc.cnt
  FROM broker_metrics bm, broker_count bc WHERE bm.broker_slug = p_broker_slug
  UNION ALL
  SELECT 'conv_rate'::text, bm.conv_rate,
    ROUND((PERCENT_RANK() OVER (ORDER BY bm.conv_rate) * 100)::numeric, 1),
    bc.cnt
  FROM broker_metrics bm, broker_count bc WHERE bm.broker_slug = p_broker_slug;
$function$;

