CREATE OR REPLACE FUNCTION public.refresh_broker_review_stats()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO public.broker_review_stats (broker_id, review_count, average_rating, updated_at)
  SELECT
    COALESCE(NEW.broker_id, OLD.broker_id),
    COUNT(*),
    COALESCE(ROUND(AVG(rating)::numeric, 1), 0),
    now()
  FROM public.user_reviews
  WHERE broker_id = COALESCE(NEW.broker_id, OLD.broker_id)
    AND status = 'approved'
  ON CONFLICT (broker_id)
  DO UPDATE SET
    review_count   = EXCLUDED.review_count,
    average_rating = EXCLUDED.average_rating,
    updated_at     = now();

  RETURN COALESCE(NEW, OLD);
END;
$function$;

CREATE OR REPLACE FUNCTION public.refresh_placement_stats()
 RETURNS void
 LANGUAGE sql
 SET search_path TO ''
AS $function$
  UPDATE marketplace_placements mp SET
    monthly_impressions = COALESCE(agg.total_impressions, 0),
    avg_ctr_pct = CASE WHEN COALESCE(agg.total_impressions, 0) > 0
                  THEN ROUND((COALESCE(agg.total_clicks, 0)::numeric / agg.total_impressions) * 100, 2)
                  ELSE 0 END,
    stats_updated_at = now()
  FROM (
    SELECT c.placement_id,
           SUM(cds.impressions)::int as total_impressions,
           SUM(cds.clicks)::int as total_clicks
    FROM campaign_daily_stats cds
    JOIN campaigns c ON c.id = cds.campaign_id
    WHERE cds.stat_date >= (CURRENT_DATE - INTERVAL '30 days')::date
    GROUP BY c.placement_id
  ) agg
  WHERE mp.id = agg.placement_id;
$function$;

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$;

CREATE OR REPLACE FUNCTION public.search_advisors_nearby(p_lat double precision, p_lng double precision, p_radius_km integer DEFAULT 25, p_type text DEFAULT NULL::text, p_fee_structure text DEFAULT NULL::text, p_specialty text DEFAULT NULL::text, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0)
 RETURNS TABLE(id integer, slug text, name text, firm_name text, type text, specialties jsonb, location_state text, location_suburb text, location_display text, location_postcode text, photo_url text, fee_structure text, fee_description text, hourly_rate_cents integer, flat_fee_cents integer, aum_percentage numeric, initial_consultation_free boolean, rating numeric, review_count integer, verified boolean, offer_text text, offer_active boolean, distance_km double precision)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    p.id, p.slug, p.name, p.firm_name, p.type, p.specialties,
    p.location_state, p.location_suburb, p.location_display, p.location_postcode,
    p.photo_url, p.fee_structure, p.fee_description,
    p.hourly_rate_cents, p.flat_fee_cents, p.aum_percentage, p.initial_consultation_free,
    p.rating, p.review_count, p.verified,
    p.offer_text, p.offer_active,
    ROUND((ST_Distance(p.geog, ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography) / 1000.0)::numeric, 1)::double precision AS distance_km
  FROM professionals p
  WHERE p.status = 'active'
    AND p.geog IS NOT NULL
    AND ST_DWithin(p.geog, ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography, p_radius_km * 1000)
    AND (p_type IS NULL OR p.type = p_type)
    AND (p_fee_structure IS NULL OR p.fee_structure = p_fee_structure)
    AND (p_specialty IS NULL OR p.specialties @> jsonb_build_array(p_specialty))
  ORDER BY distance_km ASC, p.rating DESC NULLS LAST
  LIMIT p_limit OFFSET p_offset;
END;
$function$;

CREATE OR REPLACE FUNCTION public.search_embeddings_knn(query_embedding vector, match_limit integer DEFAULT 10, match_type text DEFAULT NULL::text)
 RETURNS TABLE(document_type text, document_id text, title text, body_excerpt text, distance numeric)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT
    se.document_type,
    se.document_id,
    se.title,
    se.body_excerpt,
    (se.embedding <=> query_embedding)::numeric AS distance
  FROM public.search_embeddings se
  WHERE match_type IS NULL OR se.document_type = match_type
  ORDER BY se.embedding <=> query_embedding
  LIMIT LEAST(match_limit, 50);
$function$;

