  ELSIF (TG_OP = 'DELETE') THEN
    UPDATE public.user_lists SET item_count = GREATEST(item_count - 1, 0) WHERE id = OLD.list_id;
  END IF;
  RETURN NULL;
END;
$function$;


-- ===== VIEWS =====

-- SECTION: Views (non-PostGIS, non-Supabase-internal)

CREATE OR REPLACE VIEW public.account_kind_membership AS
 SELECT
    s.user_id,
    max(s.status) AS subscription_status,
    bool_or((s.status = ANY (ARRAY['active'::text, 'trialing'::text]))) AS is_pro
   FROM subscriptions s
  WHERE (s.current_period_end > now())
  GROUP BY s.user_id;

CREATE OR REPLACE VIEW public.admin_advisor_health AS
 SELECT
    p.id,
    p.slug,
    p.name,
    p.status,
    p.type,
    p.verified,
    p.rating,
    p.review_count,
    p.lead_count,
    p.created_at,
    p.updated_at,
    count(DISTINCT al.id) AS leads_last_30d,
    count(DISTINCT ab.id) AS unpaid_bills,
    sum(ab.amount_cents) FILTER (WHERE (ab.status = 'pending'::text)) AS unpaid_amount_cents
   FROM ((professionals p
     LEFT JOIN professional_leads al ON (((al.professional_id = p.id) AND (al.created_at > (now() - '30 days'::interval)))))
     LEFT JOIN advisor_billing ab ON ((ab.professional_id = p.id)))
  GROUP BY p.id, p.slug, p.name, p.status, p.type, p.verified, p.rating, p.review_count, p.lead_count, p.created_at, p.updated_at;

CREATE OR REPLACE VIEW public.connection_pool_snapshot AS
 SELECT
    pg_stat_activity.wait_event_type,
    pg_stat_activity.wait_event,
    pg_stat_activity.state,
    count(*) AS count
   FROM pg_stat_activity
  GROUP BY pg_stat_activity.wait_event_type, pg_stat_activity.wait_event, pg_stat_activity.state;

CREATE OR REPLACE VIEW public.finance_monthly_summary AS
 SELECT
    date_trunc('month'::text, (wf.created_at)::timestamp with time zone) AS month,
    wf.type,
    wf.broker_slug,
    count(*) AS transaction_count,
    sum(wf.amount_cents) AS total_cents
   FROM wallet_transactions wf
  GROUP BY (date_trunc('month'::text, (wf.created_at)::timestamp with time zone)), wf.type, wf.broker_slug
  ORDER BY (date_trunc('month'::text, (wf.created_at)::timestamp with time zone)) DESC;

CREATE OR REPLACE VIEW public.firm_credit_balance_summary AS
 SELECT
    p.id AS professional_id,
    p.firm_name,
    p.slug,
    COALESCE(sum(wt.amount_cents) FILTER (WHERE (wt.type = 'credit'::text)), (0)::bigint) AS total_credits_cents,
    COALESCE(sum(wt.amount_cents) FILTER (WHERE (wt.type = 'debit'::text)), (0)::bigint) AS total_debits_cents,
    (COALESCE(sum(wt.amount_cents) FILTER (WHERE (wt.type = 'credit'::text)), (0)::bigint) - COALESCE(sum(wt.amount_cents) FILTER (WHERE (wt.type = 'debit'::text)), (0)::bigint)) AS balance_cents
   FROM (professionals p
     LEFT JOIN wallet_transactions wt ON ((wt.broker_slug = p.slug)))
  GROUP BY p.id, p.firm_name, p.slug;

CREATE OR REPLACE VIEW public.posthog_daily_funnel AS
 SELECT
    (date_trunc('day'::text, (ae.created_at)::timestamp with time zone))::date AS day,
    count(*) FILTER (WHERE (ae.event_type = 'page_view'::text)) AS page_views,
    count(*) FILTER (WHERE (ae.event_type = 'broker_click'::text)) AS broker_clicks,
    count(*) FILTER (WHERE (ae.event_type = 'cta_click'::text)) AS cta_clicks,
    count(DISTINCT ae.session_id) AS sessions
   FROM analytics_events ae
  WHERE (ae.created_at >= (now() - '30 days'::interval))
  GROUP BY ((date_trunc('day'::text, (ae.created_at)::timestamp with time zone))::date)
  ORDER BY ((date_trunc('day'::text, (ae.created_at)::timestamp with time zone))::date);

CREATE OR REPLACE VIEW public.product_user_verified_counts AS
 SELECT
    u.product_slug,
    count(DISTINCT u.user_id) AS verified_count
   FROM product_user_verified u
  GROUP BY u.product_slug;

CREATE OR REPLACE VIEW public.rba_poll_accuracy AS
 SELECT
    rp.meeting_date,
    rp.direction_predicted,
    rp.direction_actual,
    rp.direction_correct,
    rp.magnitude_predicted_bps,
    rp.magnitude_actual_bps,
    rp.magnitude_error_bps,
    count(DISTINCT ra.id) AS response_count,
    round(avg(
        CASE ra.prediction
            WHEN 'hold'::text THEN 0
            WHEN 'cut_25'::text THEN (-25)
            WHEN 'cut_50'::text THEN (-50)
            WHEN 'hike_25'::text THEN 25
            WHEN 'hike_50'::text THEN 50
            ELSE NULL::integer
        END)::numeric, 1) AS avg_crowd_bps
   FROM (rba_polls rp
     LEFT JOIN rba_poll_answers ra ON ((ra.poll_id = rp.id)))
  WHERE (rp.direction_actual IS NOT NULL)
  GROUP BY rp.meeting_date, rp.direction_predicted, rp.direction_actual, rp.direction_correct, rp.magnitude_predicted_bps, rp.magnitude_actual_bps, rp.magnitude_error_bps
  ORDER BY rp.meeting_date DESC;

CREATE OR REPLACE VIEW public.slow_query_snapshot AS
 SELECT
    pg_stat_statements.query,
    pg_stat_statements.calls,
    round((pg_stat_statements.mean_exec_time)::numeric, 2) AS mean_ms,
    round((pg_stat_statements.total_exec_time)::numeric, 2) AS total_ms,
    round((pg_stat_statements.stddev_exec_time)::numeric, 2) AS stddev_ms
   FROM pg_stat_statements
  WHERE (pg_stat_statements.mean_exec_time > (100)::double precision)
  ORDER BY pg_stat_statements.mean_exec_time DESC
 LIMIT 50;


-- ===== MATERIALIZED VIEWS =====

-- SECTION: Materialized Views

CREATE MATERIALIZED VIEW IF NOT EXISTS public.advisor_cohort_metrics AS
 SELECT
    date_trunc('month'::text, (p.created_at)::timestamp with time zone) AS cohort_month,
    p.type AS advisor_type,
    count(*) AS total_advisors,
    count(*) FILTER (WHERE (p.status = 'active'::text)) AS active_advisors,
    count(*) FILTER (WHERE (p.verified = true)) AS verified_advisors,
    round(avg(p.rating), 2) AS avg_rating,
    sum(p.lead_count) AS total_leads,
    round(avg(p.lead_count::numeric), 1) AS avg_leads_per_advisor,
    count(*) FILTER (WHERE (p.initial_consultation_free = true)) AS free_consult_count,
    count(*) FILTER (WHERE (p.offer_active = true)) AS with_offer_count
   FROM professionals p
  GROUP BY (date_trunc('month'::text, (p.created_at)::timestamp with time zone)), p.type
  ORDER BY (date_trunc('month'::text, (p.created_at)::timestamp with time zone)) DESC, p.type
  WITH NO DATA;


