-- ===== POLICIES (1-300) =====

CREATE POLICY "service_role full access" ON public._slug_fix_log AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Service role manages ab_tests" ON public.ab_tests AS PERMISSIVE FOR ALL TO public USING ((( SELECT auth.role() AS role) = 'service_role'::text)) WITH CHECK ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY account_deletion_requests_self_cancel ON public.account_deletion_requests AS PERMISSIVE FOR UPDATE TO public USING (((user_id = auth.uid()) AND (status = ANY (ARRAY['scheduled'::text, 'cancelled'::text])))) WITH CHECK (((user_id = auth.uid()) AND (status = ANY (ARRAY['scheduled'::text, 'cancelled'::text]))));
CREATE POLICY account_deletion_requests_self_insert ON public.account_deletion_requests AS PERMISSIVE FOR INSERT TO public WITH CHECK ((user_id = auth.uid()));
CREATE POLICY account_deletion_requests_self_read ON public.account_deletion_requests AS PERMISSIVE FOR SELECT TO public USING ((user_id = auth.uid()));
CREATE POLICY "service_role full access" ON public.admin_action_log AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Admin can insert audit log" ON public.admin_audit_log AS PERMISSIVE FOR INSERT TO authenticated WITH CHECK (is_admin());
CREATE POLICY "Admin can read audit log" ON public.admin_audit_log AS PERMISSIVE FOR SELECT TO authenticated USING (is_admin());
CREATE POLICY "Service role full access admin_impersonations" ON public.admin_impersonations AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Service role only on admin_login_attempts" ON public.admin_login_attempts AS PERMISSIVE FOR ALL TO public USING (false);
CREATE POLICY "service_role full access" ON public.admin_mfa_enrollments AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Admins read applications" ON public.advisor_applications AS PERMISSIVE FOR SELECT TO public USING (is_admin());
CREATE POLICY "Public can apply with required fields" ON public.advisor_applications AS PERMISSIVE FOR INSERT TO public WITH CHECK (((name IS NOT NULL) AND (email IS NOT NULL) AND (length(name) > 1) AND (length(email) > 5)));
CREATE POLICY "Service role updates applications" ON public.advisor_applications AS PERMISSIVE FOR UPDATE TO service_role USING (true);
CREATE POLICY "Service role only mod log" ON public.advisor_article_moderation_log AS PERMISSIVE FOR ALL TO public USING (false);
CREATE POLICY "Anyone can read published articles" ON public.advisor_articles AS PERMISSIVE FOR SELECT TO public USING ((status = 'published'::text));
CREATE POLICY "Service role inserts articles" ON public.advisor_articles AS PERMISSIVE FOR INSERT TO service_role WITH CHECK (true);
CREATE POLICY "Service role manages all articles" ON public.advisor_articles AS PERMISSIVE FOR ALL TO service_role USING (true);
CREATE POLICY "Service role updates articles" ON public.advisor_articles AS PERMISSIVE FOR UPDATE TO service_role USING (true);
CREATE POLICY "Advisors read own bids" ON public.advisor_auction_bids AS PERMISSIVE FOR SELECT TO public USING ((advisor_id IN ( SELECT professionals.id
   FROM professionals
  WHERE (professionals.auth_user_id = auth.uid()))));
CREATE POLICY "Service role full access auction_bids" ON public.advisor_auction_bids AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Public read of public open auctions" ON public.advisor_auctions AS PERMISSIVE FOR SELECT TO public USING (((is_public = true) AND (flow_type = 'auction'::text) AND (status = 'open'::text)));
CREATE POLICY "Service role full access advisor_auctions" ON public.advisor_auctions AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Service manage auth tokens" ON public.advisor_auth_tokens AS PERMISSIVE FOR ALL TO public USING ((( SELECT auth.role() AS role) = 'service_role'::text)) WITH CHECK ((( SELECT auth.role() AS role) = 'service_role'::text));
CREATE POLICY "Service role manages auth tokens" ON public.advisor_auth_tokens AS PERMISSIVE FOR ALL TO service_role USING (true);
CREATE POLICY advisor_badges_public_read ON public.advisor_badges AS PERMISSIVE FOR SELECT TO public USING (true);
CREATE POLICY advisor_badges_service_role ON public.advisor_badges AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Admins read all billing" ON public.advisor_billing AS PERMISSIVE FOR SELECT TO public USING (is_admin());
CREATE POLICY "Advisor can view own billing" ON public.advisor_billing AS PERMISSIVE FOR SELECT TO authenticated USING ((professional_id IN ( SELECT professionals.id
   FROM professionals
  WHERE (professionals.auth_user_id = auth.uid()))));
CREATE POLICY "Service role can insert billing" ON public.advisor_billing AS PERMISSIVE FOR INSERT TO service_role WITH CHECK (true);
CREATE POLICY "service_role full access billing" ON public.advisor_billing AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "service_role full access" ON public.advisor_booking_appointments AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY "Public can read booking slots" ON public.advisor_booking_slots AS PERMISSIVE FOR SELECT TO public USING (true);
CREATE POLICY "Service role manages booking slots" ON public.advisor_booking_slots AS PERMISSIVE FOR ALL TO service_role USING (true);
CREATE POLICY "Admins read bookings" ON public.advisor_bookings AS PERMISSIVE FOR SELECT TO public USING (is_admin());
CREATE POLICY "Public can create bookings" ON public.advisor_bookings AS PERMISSIVE FOR INSERT TO public WITH CHECK ((professional_id IS NOT NULL));
CREATE POLICY "Service role manages bookings" ON public.advisor_bookings AS PERMISSIVE FOR ALL TO service_role USING (true);
CREATE POLICY case_studies_owner_write ON public.advisor_case_studies AS PERMISSIVE FOR ALL TO authenticated USING ((professional_id IN ( SELECT professionals.id
   FROM professionals
  WHERE (professionals.auth_user_id = auth.uid())))) WITH CHECK ((professional_id IN ( SELECT professionals.id
   FROM professionals
  WHERE (professionals.auth_user_id = auth.uid()))));
CREATE POLICY case_studies_public_read ON public.advisor_case_studies AS PERMISSIVE FOR SELECT TO public USING ((status = 'published'::text));
CREATE POLICY case_studies_service_role ON public.advisor_case_studies AS PERMISSIVE FOR ALL TO service_role USING (true) WITH CHECK (true);
CREATE POLICY advisor_certifications_owner_write ON public.advisor_certifications AS PERMISSIVE FOR ALL TO authenticated USING ((professional_id IN ( SELECT professionals.id
   FROM professionals
  WHERE (professionals.auth_user_id = auth.uid())))) WITH CHECK ((professional_id IN ( SELECT professionals.id
