-- ===== GRANTS AND EVENT TRIGGERS =====

-- SECTION: Schema grants + event triggers

GRANT USAGE ON SCHEMA public TO anon, authenticated, service_role;

-- Event triggers (reference Supabase-internal functions; harmless on fresh Supabase project)
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_event_trigger WHERE evtname = 'ensure_rls') THEN
    EXECUTE $t$CREATE EVENT TRIGGER ensure_rls ON ddl_command_end WHEN TAG IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO') EXECUTE FUNCTION rls_auto_enable()$t$;
  END IF;
END $$;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_event_trigger WHERE evtname = 'issue_graphql_placeholder') THEN
    EXECUTE $t$CREATE EVENT TRIGGER issue_graphql_placeholder ON sql_drop WHEN TAG IN ('DROP EXTENSION') EXECUTE FUNCTION set_graphql_placeholder()$t$;
  END IF;
EXCEPTION WHEN undefined_function THEN NULL;
END $$;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_event_trigger WHERE evtname = 'issue_pg_cron_access') THEN
    EXECUTE $t$CREATE EVENT TRIGGER issue_pg_cron_access ON ddl_command_end WHEN TAG IN ('CREATE EXTENSION') EXECUTE FUNCTION grant_pg_cron_access()$t$;
  END IF;
EXCEPTION WHEN undefined_function THEN NULL;
END $$;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_event_trigger WHERE evtname = 'issue_pg_graphql_access') THEN
    EXECUTE $t$CREATE EVENT TRIGGER issue_pg_graphql_access ON ddl_command_end WHEN TAG IN ('CREATE FUNCTION') EXECUTE FUNCTION grant_pg_graphql_access()$t$;
  END IF;
EXCEPTION WHEN undefined_function THEN NULL;
END $$;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_event_trigger WHERE evtname = 'issue_pg_net_access') THEN
    EXECUTE $t$CREATE EVENT TRIGGER issue_pg_net_access ON ddl_command_end WHEN TAG IN ('CREATE EXTENSION') EXECUTE FUNCTION grant_pg_net_access()$t$;
  END IF;
EXCEPTION WHEN undefined_function THEN NULL;
END $$;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_event_trigger WHERE evtname = 'pgrst_ddl_watch') THEN
    EXECUTE $t$CREATE EVENT TRIGGER pgrst_ddl_watch ON ddl_command_end EXECUTE FUNCTION pgrst_ddl_watch()$t$;
  END IF;
EXCEPTION WHEN undefined_function THEN NULL;
END $$;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_event_trigger WHERE evtname = 'pgrst_drop_watch') THEN
    EXECUTE $t$CREATE EVENT TRIGGER pgrst_drop_watch ON sql_drop EXECUTE FUNCTION pgrst_drop_watch()$t$;
  END IF;
EXCEPTION WHEN undefined_function THEN NULL;
END $$;
